using Microsoft.EntityFrameworkCore;
class AppDbContext : DbContext
{
    public DbSet<Order> Orders => Set<Order>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change: HasData seed values must be deterministic.
        // DateTime.UtcNow is non-deterministic and now throws at build time.
        modelBuilder.Entity<Order>().HasData(
            new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });

        // EF Core 9 breaking change (Cosmos provider): The discriminator property
        // is now named "$type" instead of "Discriminator". For existing documents
        // that already store "Discriminator", override back to the old name:
        modelBuilder.Entity<Order>().HasDiscriminator<string>("Discriminator");
    }
}
class Order { public int Id { get; set; } public DateTime CreatedAt { get; set; } }

