using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF Core 9 breaking change: Migrate() now throws if called inside a
    // user-opened transaction because it manages its own transactions internally.
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }

    // EF Core 9 breaking change (Cosmos provider): Synchronous query execution
    // (e.g., ToList(), First()) now throws InvalidOperationException.
    // All Cosmos queries must use async equivalents (ToListAsync, FirstAsync, etc.).
    async Task QueryCosmosAsync(AppDbContext db)
    {
        // WRONG in EF Core 9: var orders = db.Orders.ToList();
        var orders = await db.Orders.ToListAsync();
    }
}

